package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnPostUpdateProxy struct {
	automation.UnimplementedOnPostUpdateServer
	client automation.OnPostUpdateClient
}

func init() {
	proxyutil.Register(&automation.OnPostUpdate_ServiceDesc, NewOnPostUpdateProxy)
}
func NewOnPostUpdateProxy(cc grpc.ClientConnInterface) automation.OnPostUpdateServer {
	return &OnPostUpdateProxy{client: automation.NewOnPostUpdateClient(cc)}
}
func (p *OnPostUpdateProxy) OnPostUpdate(ctx context.Context, in *events.PostUpdate) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.PostUpdate, automation.HandlerResult](p.client.OnPostUpdate)(ctx, in)
}
